import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NUMBERS = {
    "4": {
        "1": "<p>The third Levitical census (ch1 counted Israel for war, ch3 counted all Levites for their replacement role, ch4 counts the service-age Levites for active tabernacle transport). The double address to Moses and Aaron signals that this census involves priestly supervision — Aaron's sons oversee the actual covering of the holy objects before the Levites may carry them.</p>",
        "2": "<p>The Kohathites are counted first because they carry the most holy objects. The census is organized <em>leḇêt ʾăḇōtām</em> — by ancestral houses — within the broader clan structure, reflecting the patrilineal organization of Israelite society that also determines inheritance, land allocation, and levitical assignments throughout Numbers.</p>",
        "3": "<p>The age bracket 30–50 (<em>mibbɛn šəlōšîm šānâ wamaʿəlâ wəʿad ben-ḥămiššîm šānâ</em>) defines the period of full active service. Later in 8:24-25 the age of entry is set at 25 for preliminary service, and at 50 one retires from transport service. The 30-year minimum aligns with when a priest could begin full ministry in later tradition (Luke 3:23 notes Jesus began ministry at approximately this age, echoing the Levitical-priestly pattern).</p>",
        "4": "<p>The Kohathites are assigned the most holy objects (<em>qōḏeš haqqǒḏāšîm</em>). In the P tradition's holiness gradient, the holy of holies is the most sacred space and its contents the most sacred objects. Kohathite privilege — carrying the ark, table, lampstand, altars — is matched by extraordinary danger: they must not touch or see the holy things (vv15,20) on pain of death.</p>",
        "5": "<p>The covering procedure begins with Aaron and his sons (the priests): they must wrap everything before the Kohathites arrive. The inner veil (<em>pārōket hamāsāk</em>) — the curtain separating the holy of holies from the holy place — comes down first and wraps the ark of the covenant. The ark cannot be approached by Kohathites until it is already covered by the priests; even the high privilege of transport comes with this mediating barrier.</p>",
        "6": "<p>Three layers protect the ark: the inner veil (v5), a fine leather covering (<em>ʿôr tāḥaš</em> — perhaps dugong or porpoise hide, a durable water-resistant material), and a blue cloth (<em>bəgeḏ kəlîl təkēlet</em>) on the outside. The visible outer cloth is blue — the color associated with the sky and with priestly/royal dignity throughout the tabernacle (Exod 25:4; 28:5). The ark presents as a blue-wrapped object to the Kohathite carriers, with no gold or sacred form visible.</p>",
        "7": "<p>The table of the Presence (<em>šulḥan happānîm</em>) — the showbread table — is covered in blue cloth with its dishes, plates, bowls, and cups left on it. The table's sacred service items remain in place during transport, maintained in their cultic arrangement even while in transit. This preserves the ritual order within the movement of the whole sanctuary.</p>",
        "8": "<p>The table covering adds a scarlet cloth over the blue — the only object with this double-cloth arrangement in ch4. Red/scarlet (<em>šānî tôlaʿat</em>) was used in purification rites (Lev 14; Num 19) and in tabernacle construction (Exod 25:4). The leather covering goes over the scarlet. The table thus has the most elaborate wrapping: blue (inner), scarlet (middle), leather (outer).</p>",
        "9": "<p>The lampstand (<em>mənorat hammāʾôr</em>) and all its accessories — snuffers, trays, oil vessels — are wrapped in blue cloth. The lampstand is the only object in the tabernacle with continuous function (it burns perpetually, Exod 27:20-21); its transport covering puts its fire out, with all implements gathered for protection. The lampstand's transport symbolizes the temporary suspension of the divine light during movement.</p>",
        "10": "<p>The lampstand assembly is placed on a carrying frame (<em>môṭ</em>) within the leather covering. The <em>môṭ</em> — carrying pole/frame — appears for the lampstand and for the table (v8) as distinct from the carrying poles (<em>baddîm</em>) used for the ark and altars. The distinction reflects different modes of transport for different categories of sacred furniture.</p>",
        "11": "<p>The golden altar of incense (<em>mizbaḥ hazzāhāḇ</em>) is covered in blue cloth and leather — the same covering combination as the ark (vv5-6). The incense altar's blue outer covering gives it visual parity with the ark during transport, signaling its high status among the holy objects. The incense altar stood directly before the veil in the holy place, making it the closest non-ark object to the divine presence.</p>",
        "12": "<p>All the utensils of ministry (<em>kəlê haššərēt</em>) used in the sanctuary are gathered into a blue cloth, covered in leather, and placed on the carrying frame. The comprehensive gathering ensures no sacred vessel is left behind or transported separately outside the covered Kohathite loads.</p>",
        "13": "<p>The bronze altar of burnt offering (<em>mizbaḥ hannəḥōšet</em>) presents a unique challenge: it is full of ashes from the daily burnt offerings. The ashes must be removed (<em>ûdišnû ʾet-hammizbēaḥ</em>) and a purple cloth spread over it. Purple (<em>ʾargāmān</em>) — a dye from Murex sea snails, extremely expensive in antiquity — covers the bronze altar, whose status as the most used sacrificial object earns it distinct treatment.</p>",
        "14": "<p>All the bronze altar's utensils — fire pans (<em>maḥtōt</em>), forks (<em>mizlāgōt</em>), shovels (<em>yaʿîm</em>), basins (<em>mizrāqōt</em>), the grating — are placed on the purple-covered altar before the leather covering goes over everything. The implements of blood and fire are treated with the same ritual care as the objects of incense and bread in the holy place.</p>",
        "15": "<p>The critical verse: only after Aaron and his sons finish covering everything may the Kohathites come and lift (<em>ûnəśāʾû hakkəhātîm</em>). But they must not touch (<em>wəlōʾ-yiggəʿû ʾel-haqqōḏeš</em>) the holy things; death follows from touching. The word <em>wāmētû</em> — and they shall die — is the same death-warning used for unauthorized priestly and lay approach throughout Leviticus and Numbers. The privilege of proximity is precisely what makes the danger real.</p>",
        "16": "<p>Eleazar son of Aaron has oversight of the entire service: the oil of the light, the fragrant incense, the regular grain offering, and the anointing oil. These are the items requiring continuous provision and priestly management. Eleazar's role as administrator over the whole tabernacle service anticipates his later position as chief priest after Aaron's death (Num 20:25-28).</p>",
        "17": "<p>A fresh divine speech addresses a specific danger unique to the Kohathites. The warning is directed at Moses and Aaron — the leaders must take action to protect the Kohathite clan from being cut off (<em>yikkārēt šēḇeṭ mišpəḥōt haqqəhātî</em>).</p>",
        "18": "<p><em>ʾal-tašmîdû ʾet-šēḇeṭ mišpəḥōt haqqəhātî mittôk halwiyyim</em> — do not let the Kohathite clan be destroyed from among the Levites. The warning addresses the structural irony: those most privileged in the Levitical hierarchy (Kohath is the clan of Moses and Aaron, Exod 6:18-20) face the greatest risk of death from their very assignment. Special privilege and special danger coincide throughout the P legislation.</p>",
        "19": "<p>The protective procedure: Aaron and his sons shall assign each man to his specific task and his specific load. The individualized assignment prevents any Kohathite from being in the wrong place at the wrong time relative to the uncovered holy objects. The protective procedure is not ritual but organizational: careful priestly administration is what keeps the Kohathites alive.</p>",
        "20": "<p><em>wəlōʾ-yāḇōʾû lirʾôt kəballēaʿ ʾet-haqqōḏeš wāmētû</em> — they must not go in to look at the holy things even for a moment, or they will die. The word <em>kəballēaʿ</em> — even for a moment/as in swallowing — suggests the briefest visual contact with the unwrapped holy objects is fatal. This is not mere metaphor: Uzzah's death when touching the ark (2 Sam 6:6-7) and the death of the Bethshemeshites who looked into the ark (1 Sam 6:19) narrate exactly this principle as historical reality.</p>",
        "21": "<p>The Gershonite census commands follow the Kohathite section. The three-part structure of ch4 — Kohath, Gershon, Merari — mirrors the clan hierarchy established in ch3, where Kohath's position in the middle physically (the most central location around the tabernacle) reflects its cultic centrality.</p>",
        "22": "<p>The Gershonites are counted by the same method: ancestral houses, clans. The administrative uniformity across the three Levitical censuses reflects the P tradition's systematic approach to organization — each clan is processed through the same bureaucratic procedure even though their assignments differ considerably.</p>",
        "23": "<p>The same 30–50 age bracket applies to the Gershonites. The phrase <em>kol-bāʾ liṣbōʾ ṣāḇāʾ laʿăḇōḏ ʿăḇōḏâ</em> — all who qualify to serve, to do work — uses the military conscription vocabulary (<em>ṣāḇāʾ</em> = host/army) for the Levitical service. The Levites' tabernacle work is framed as a form of military service, with the same age requirement and organizational structure.</p>",
        "24": "<p>The Gershonite assignment: <em>ʿăḇōḏâ ûmassāʾ</em> — service and carrying. The two-term description distinguishes service (cultic duties) from carrying (physical transport), though for the Gershonites these are unified: their service is defined by carrying the fabric components of the tabernacle.</p>",
        "25": "<p>The Gershonite load: the tabernacle's curtains (<em>yərîʿōt hammiškān</em>), the tent covering (<em>ʾōhel môʿēd</em>), the leather outer covering, the screen (<em>māsāk</em>) for the tent entrance. These are the fabric elements that defined the space of the sanctuary; the Kohathites carry the holy furniture inside the space, while the Gershonites carry the space itself.</p>",
        "26": "<p>The courtyard hangings (<em>qalʿê heḥāṣēr</em>), the screen at the gate, and all the cords (<em>kol-yōtēdōt</em>) are part of the Gershonite load. Everything made of woven or natural fiber — linen, wool, goat hair — belongs to Gershon. The Gershonites' work is lighter in symbolic terms (they carry the outer rather than the inner) but enormous in physical scale: the combined curtain surface of the tabernacle was massive.</p>",
        "27": "<p>All Gershonite work — in carrying and in all service (<em>kol-ʿăḇōḏōtām ûlkol-massāʾām</em>) — is done under Aaron and his sons' direction. The Gershonites have no independent authority; they receive their assignments from Ithamar son of Aaron (v28). The Levitical clans function as organized labor under priestly supervision throughout the P system.</p>",
        "28": "<p>Ithamar son of Aaron oversees the Gershonites. The assignment of Eleazar to the Kohathites (v16) and Ithamar to the Gershonites and Merarites (v33) reflects the division of priestly supervisory responsibility between Aaron's two remaining sons after Nadab and Abihu died (Lev 10:1-2). The administrative structure accommodates the reduced priestly family.</p>",
        "29": "<p>The Merarite census follows the same formula as the other two clans. The Merarites were historically the largest of the three Levitical clans (ch3: 6,200 vs. Kohath's 8,600 and Gershon's 7,500 — Merarites were second largest by total count), and the active-service census confirms their substantial numbers (v44: 3,200).</p>",
        "30": "<p>Same age bracket (30–50) for the Merarites. The uniformity of age requirements across all three clans establishes that mature physical capacity (both for the heavy work and for the responsibility) is the baseline requirement for tabernacle transport service regardless of the specific assignment.</p>",
        "31": "<p>The Merarite load: the structural hardware of the tabernacle — frames (<em>qərāšîm</em>), bars (<em>bərîḥîm</em>), pillars (<em>ʿammûḏîm</em>), and bases (<em>ʾăḏānîm</em>). While the Kohathites carried the most sacred content and the Gershonites carried the fabric envelope, the Merarites carried the skeleton — the heavy wood and metal framework that gave the tabernacle its structural integrity. Their load was probably the heaviest physically.</p>",
        "32": "<p>The surrounding courtyard pillars, their bases, pegs (<em>yōtēḏōt</em>), and ropes (<em>mêtārîm</em>) — all the hardware for the exterior — belong to Merarites. The detailed list of articles, with each man assigned to specific items by name, reflects the P tradition's careful inventory control. Specific assignment prevents any equipment from being lost in transit or claimed by the wrong carrier.</p>",
        "33": "<p>The Merarite work falls under Ithamar's supervision (parallel to the Gershonites, v28). The two less-holy clans are both supervised by the younger surviving Aaronic son. This administrative arrangement proved practically significant: Ithamar's line eventually housed the Eli priesthood (1 Sam 2:27-36) at Shiloh and beyond.</p>",
        "34": "<p>The census execution begins: Moses, Aaron, and the leaders count the Kohathites. The communal leadership (the same tribal leaders who administered the ch1 census) participates again here, making the Levitical service-census a matter of public record and communal accountability, not merely internal Levitical administration.</p>",
        "35": "<p>The count is defined with precision: age 30-50, all who qualified for service in the tent of meeting. The census criteria are explicit in the repetition — the count will be precise and limited to exactly those who meet the service-age requirement.</p>",
        "36": "<p>Kohathite service-age count: 2,750. The ch3 Kohathite total was 8,600 (all males, one month and up). The service-age cohort (30-50) is 2,750 — approximately 32% of the total — consistent with the service-age fraction one would expect in a living population given ancient mortality patterns.</p>",
        "37": "<p>The closing summary formula: counted by Moses and Aaron at YHWH's command through Moses. Each clan census closes with the same attribution — divine command through Moses, executed by Moses and Aaron. The census data is thereby classified as covenant compliance rather than administrative routine.</p>",
        "38": "<p>The Gershonite census results follow the same structure. The census of Gershon (vv38-41) mirrors Kohath exactly: the same formula, the same age bracket, the same attribution to divine command.</p>",
        "39": "<p>The Gershonite service-age count begins with the same qualifier: all from 30-50 who qualified to work in the tent of meeting. The uniform criteria applied across all three clans ensures that the combined total (v46-48) represents a consistent category.</p>",
        "40": "<p>Gershonite service-age count: 2,630. Slightly smaller than the Kohathite count despite Gershon being slightly larger overall — the ratio of service-age males to total males was apparently lower, reflecting natural demographic variation between the clans.</p>",
        "41": "<p>Same attribution formula: counted by Moses and Aaron at YHWH's command. The repetition of the formula three times — once per clan — emphasizes that each clan's census was a discrete act of covenantal compliance, not a single procedure applied uniformly.</p>",
        "42": "<p>The Merarite census follows. Despite being the structurally heaviest-load clan, the Merarites receive the same administrative treatment as the other clans. The P tradition's egalitarian procedural application — same formulas, same criteria, same attribution — reflects an ideology of uniform covenantal obligation across all Levitical clans.</p>",
        "43": "<p>Same age bracket, same qualification criteria. The Merarites who qualify for active transport service will be individually assigned their specific loads (v32) — the most granular assignment in all of ch4.</p>",
        "44": "<p>Merarite service-age count: 3,200. This is the largest service-age count of the three clans (Kohath: 2,750; Gershon: 2,630; Merari: 3,200), a reversal from the ch3 total-count ranking (Kohath was largest overall). The Merarites' service-age proportion was apparently highest — possibly because their heavy physical work required the prime-working-age cohort more fully than the other assignments.</p>",
        "45": "<p>The Merarite census attribution mirrors the previous two clans exactly. The three closing formulas (vv37,41,45) form a structural parallel, signaling the completion of the three-clan census and preparing for the combined summary that follows.</p>",
        "46": "<p>The combined summary: all Levites enrolled by Moses, Aaron, and the Israelite leaders. This combined accounting (<em>kol-hapqûḏîm ʾăšer pāqaḏ Moshe wəʾahărōn wənəśîʾê yiśrāʾēl</em>) reflects the tripartite leadership — prophet, priest, and tribal heads — who administered the census jointly. The total represents the entire trained service-force for the tabernacle at this point in the wilderness period.</p>",
        "47": "<p>The qualification criterion for the grand total: 30-50, qualified to perform both the service work (<em>ʿăḇōḏat hāʿăḇōḏâ</em>) and the carrying work (<em>ʿăḇōḏat hammassāʾ</em>). The doubled phrase with <em>ʿăḇōḏâ</em> — service — emphasizes the integration of cultic duty and physical labor in the Levitical assignment; these are not separable functions.</p>",
        "48": "<p>Combined service-age count: 8,580 (2,750 + 2,630 + 3,200 = 8,580). The census demonstrates the scale of the tabernacle's operational personnel: nearly nine thousand trained Levites in the prime service years, organized into three clans with distinct assignments, under priestly supervision. This is the standing infrastructure of Israel's covenant worship for the forty-year wilderness period.</p>",
        "49": "<p>The concluding formula: each was enrolled at YHWH's command through Moses, each assigned to his service and his load. The phrase <em>ʾîš ʾîš ʿal-ʿăḇōḏātô wəʿal-massāʾô</em> — each man to his service and to his load — emphasizes individual assignment within the communal system. The wilderness tabernacle operated through specific, named persons with specific, defined responsibilities — a model of ordered covenantal service.</p>"
    },
    "5": {
        "1": "<p>A new divine speech unit (vv1-4) legislating the exclusion of the ritually impure from the camp. The placement immediately after the census and Levitical organization chapters (1-4) makes sense: having established who is in the camp and how it is organized, the text now addresses who must be excluded. The holiness of the camp (where YHWH dwells, v3) requires the removal of severe ritual impurity.</p>",
        "2": "<p>Three categories of exclusion: (1) <strong>מְצֹרָע (məṣōrāʿ)</strong> — person with a skin disease; Leviticus 13-14 defines this category and requires exclusion (<em>bāḏāḏ yēšēḇ</em> — he shall live alone, Lev 13:46); (2) <strong>זָב (zāḇ)</strong> — person with a bodily discharge (Lev 15); (3) <strong>טָמֵא לָנֶפֶשׁ (ṭāmēʾ lānep̄eš)</strong> — impure through corpse contact (Num 19). Together these three cover the major categories of severe ritual impurity under the Levitical system.</p>",
        "3": "<p><em>ûmizzāḵār ʿaḏ-nəqēḇâ tənašṣēʾû</em> — send them out, both male and female. The inclusion of women alongside men in the expulsion law establishes that ritual impurity is not a gendered category; the camp's holiness applies equally to all. The explicit reason: <em>wəlōʾ yəṭamməʾû ʾet-maḥănêhem ʾăšer ʾănî šōkēn bətôkām</em> — that they may not defile the camp where I dwell. YHWH's presence makes the camp a sacred space; its maintenance as such is the rationale for every purity law.</p>",
        "4": "<p>Israel's compliance: <em>wayyaʿăśû-kēn bənê yiśrāʾēl wayyəšallĕḥû ʾôtām ʾel-miḥûṣ lammaḥăneh</em> — they put them outside the camp, just as YHWH had spoken. The compliance formula closes the brief purity-exclusion unit. In context, this expulsion is temporary — the impure persons are quarantined until purification, not permanently excluded. The wilderness camp maintained a graduated perimeter: the most holy at center, the Levites surrounding, then all Israel, with the impure outside the boundary altogether.</p>",
        "5": "<p>A second divine speech unit (vv5-10) addresses unconfessed interpersonal wrongs. The new speech formula (<em>waydabber YHWH ʾel-Moshe lēmôr</em>) marks a distinct legal section covering restitution. The context — immediately after the purity laws — reflects a broad understanding of what constitutes moral pollution in the camp community.</p>",
        "6": "<p>The principle: when a man or woman commits any human sin (<em>kol-ḥaṭṭōʾt hāʾāḏām</em>), acting in breach of faith against YHWH (<em>limaʿōl maʿal ḇaYHWH</em>). The verb <strong>מָעַל (māʿal)</strong> — to trespass, act unfaithfully — is the key term for covenantal breach throughout the Torah (Lev 5:15; 26:40; Num 31:16; Deut 32:51). Sinning against a fellow person is simultaneously a trespass against YHWH — the covenant community's solidarity means harm to any member is harm to the covenant itself.</p>",
        "7": "<p>The remedial sequence: (1) <em>hithwaddâ ʾet-ḥaṭṭāʾtô ʾăšer ʿāśâ</em> — confess the sin; (2) full restitution (<em>wəhēšîḇ ʾet-ʾăšāmô bərōʾšô</em>); (3) add one-fifth (<em>wǝḥămîšîtô yôsēp̄ ʿālāyw</em>). This three-step process mirrors the guilt offering law of Lev 5:24 (Eng. 6:5) almost word-for-word; ch5 functions as the case law applying that sacrificial principle to the social realm. Confession before restitution establishes that the remedy is not merely financial but relational-covenantal.</p>",
        "8": "<p>If the wronged person has no kinsman-redeemer (<em>gōʾēl</em>) to receive restitution — because they are dead with no heir — the restitution goes to YHWH via the priest, plus the ram of atonement (<em>ʾêl hakkippurîm</em>). The scenario protects against unresolved obligations: if the wronged party's line has died out, the debt is not cancelled but transferred to the priestly system. No one can profit from a fellow person's extinction of family line.</p>",
        "9": "<p>Every gift of holy things (<em>kol-tərûmâ lekol-qoḏšê bənê yiśrāʾēl</em>) brought to the priest belongs to the priest. This verse interrupts the restitution law to clarify the priestly ownership of holy contributions, possibly introduced because v8 introduced the scenario of restitution going to the priest. The principle of priestly ownership of sacred contributions grounds the v8 provision in the broader system of priestly income.</p>",
        "10": "<p><em>wəʾîš ʾet-qoḏāšāyw lô yihyeh</em> — each person's sacred gifts belong to that person. Whatever one consecrates remains one's own responsibility until it is properly transferred to the priest. The verse clarifies that voluntary gifts are not automatically the priest's property but become so only through proper offering — protecting the worshiper from arbitrary priestly claims while ensuring the priest receives what is duly presented.</p>",
        "11": "<p>The third and most extensive law in ch5 (vv11-31): the ordeal of bitter water for the suspected unfaithful wife (<em>sotah</em> in later Jewish tradition, from <em>śātâ</em>, to go astray). This is one of the most unusual legal texts in the Torah — a formally administered divine ordeal operating within the sanctuary by priestly mediation. The law occupies 21 verses, more than the two previous laws combined, signaling its complexity and contested character.</p>",
        "12": "<p>The triggering scenario: a man's wife has gone astray (<em>tiśṭeh ʾiššô</em>) and acted unfaithfully against him (<em>māʿălâ bô māʿal</em>). The verb <em>māʿal</em> — covenant trespass — applies here to the marital covenant as a subset of the covenant with YHWH. The accusation is about suspected rather than witnessed adultery; v13 immediately specifies that the act must be secret and unwitnessed, placing the entire case in the realm of suspected but unverifiable sin.</p>",
        "13": "<p>The critical condition: the act is hidden from her husband's eyes (<em>wənistar meʿênê ʾîšāh</em>), unwitnessed (<em>wəhîʾ lōʾ nit̊p̄āśāh</em>), and she is not caught. Without witnesses, no criminal charge can proceed in the Israelite legal system (Deut 19:15: two or three witnesses required). The ordeal procedure exists precisely for this evidentiary gap: suspected but unprovable. It does not apply to cases with witnesses — those are adjudicated normally.</p>",
        "14": "<p>The husband is overcome by a <em>rûaḥ qinʾâ</em> — a spirit of jealousy/suspicion. <strong>קִנְאָה (qinʾâ)</strong> — jealousy, zeal — is used for both divine and human intense relational possessiveness (Exod 20:5; Num 25:11; Prov 6:34). Two scenarios are covered: he is jealous because she actually defiled herself, or he is jealous despite her purity. The law provides for both, with different outcomes.</p>",
        "15": "<p>The husband brings his wife to the priest with a barley grain offering — the simplest and cheapest grain offering, associated with poverty offerings (Lev 5:11) and humiliation (<em>lōʾ-yiṣōq ʿālāyw šemen wəlōʾ yittēn ʿālāyw ləḇōnâ</em> — no oil, no frankincense). The humble offering reflects the ambiguous shame of the proceeding: neither party is yet convicted, but the situation is already one of humiliation for both.</p>",
        "16": "<p>The priest presents the woman before YHWH — the proceedings are formally covenantal: this is not a human judgment but a divine ordeal. The presentation before YHWH frames the entire procedure as a divine-court proceeding, with YHWH as the effective judge of what cannot be determined by human witnesses.</p>",
        "17": "<p>The priest prepares holy water (<em>mayim qəḏōšîm</em>) in a clay vessel and adds dust from the tabernacle floor (<em>ʿāpār ʾăšer yihyeh bəqarqaʿ hammiškān</em>). The water is not chemically special — it is ceremonially charged through the tabernacle connection. The dust from the sacred floor brings the sanctity of the divine dwelling into the liquid; the mixture is a physical compound of the holy space where YHWH dwells. The clay vessel (as opposed to a gold or silver vessel) keeps the mixture outside the highest-status material categories.</p>",
        "18": "<p>The priest uncovers the woman's head (<em>ûp̄āraʿ ʾet-rōʾš hāʾiššâ</em>) — the removal of the head covering signifies either mourning/humiliation or the stripping of normal social protection, placing her in a state of complete vulnerability before the divine judgment. She holds the grain offering of jealousy while the priest holds the bitter water. The literary arrangement — her hands full of the offering while the priest holds the water — stages her between the two instruments of judgment.</p>",
        "19": "<p>The oath of innocence: if no man has lain with her (<em>ʾim-lōʾ šāḵaḇ ʾîš ʾôtāk</em>) and she has not gone astray (<em>wəʾim lōʾ śāṭît ṭumʾâ</em>), she will be free from the bitter cursing water. The conditional formula (<em>ʾim... ʾim</em>) parallels ancient Near Eastern oath structures; the woman speaks her own testimony under sacred oath. Her speech-act becomes the instrument of her own judgment.</p>",
        "20": "<p>The positive scenario of the oath: if you have gone astray and defiled yourself while under your husband's authority (<em>taḥat ʾîšek</em>), if a man other than your husband has had sexual relations with you (<em>ûttēn ʾet-šiḵbātəkā lāʾîš zûlāt ʾîšek</em>). The explicit language is functional not salacious: the law must define the precise act that triggers the curse. The phrase <em>taḥat ʾîšek</em> — under your husband — frames adultery as a violation of the covenantal subordination structure of marriage.</p>",
        "21": "<p>The priestly curse invocation: <em>yittēn YHWH ʾôtāk ləʾālâ wəliśḇûʿâ bətôk ʿammēk</em> — may YHWH make you a curse and an oath among your people. The formula invokes YHWH as the agent of any punishment that follows; the water is the instrument, YHWH is the cause. The anatomical consequence — swollen belly and falling thigh (<em>ṣəḇôt beten wənāp̄el yārēk</em>) — is debated: may refer to uterine disease, miscarriage, prolapsed uterus, or symbolic infertility. The physical consequence is specifically reproductive, matching the nature of the suspected crime.</p>",
        "22": "<p><em>wəbāʾû hammayyim hamməʾarərîm hāʾēlleh bəmeʿayiḵ</em> — may this water that brings the curse enter your body. The curse is invoked over the water itself, not merely spoken to the woman; the water becomes the carrier of covenantal judgment. The woman responds <em>ʾāmēn ʾāmēn</em> — the double affirmation of binding agreement throughout later liturgical tradition (Deut 27:15-26; Neh 8:6; 1 Cor 14:16) — making herself a co-participant in the oath rather than merely a passive subject of it.</p>",
        "23": "<p>The priest writes the curses in a scroll (<em>səp̄er</em>) and washes them into the bitter water. The written word physically dissolved into the water makes the verbal curse materially present in the liquid the woman will drink. This is sympathetic inscription — the word acts through its material carrier. The practice has ANE parallels in incantation bowls and curse tablets, but here it operates within the priestly system with YHWH as the operative agent rather than a magical formula.</p>",
        "24": "<p><em>wəhišqâ ʾet-hāʾiššâ ʾet-mê hammerār hamməʾarərîm</em> — he shall make the woman drink the bitter water that brings the curse. <em>Hammerār</em> — bitter — characterizes the water experientially (the taste) and theologically (the cursing character). The sequence — curse written, washed into water, drunk — internalizes the divine judgment literally. The curse takes up residence in her body, and YHWH judges from within.</p>",
        "25": "<p>The priest then takes the grain offering of jealousy from the woman's hands, waves it (<em>wəhēnîp̄</em>) before YHWH, and brings it to the altar. The grain offering's wave-and-altar sequence follows the standard fellowship-offering procedure (Lev 7:30-31), integrating the sotah proceeding into the regular sacrificial system. The offering acknowledges YHWH's role as judge even as the water-ordeal enacts his judgment.</p>",
        "26": "<p>The priest burns a memorial portion (<em>qomdāpṭô</em> — the customary handful) on the altar, then gives the woman the water to drink. The offering at the altar and the drinking of the water are sequential: first the communal acknowledgment of divine presence (the altar), then the individual encounter with divine judgment (the water). The sequence keeps the ordeal within the framework of regular worship.</p>",
        "27": "<p>If she is guilty, the cursing water will cause the physical consequences described in v21 — the exact fulfillment of what she agreed to in v22. The text is matter-of-fact about divine action: YHWH does the judging, the water is his instrument. The Mishnah (Sotah 9:9) reports that Yochanan ben Zakkai abolished the sotah ordeal after 70 CE, arguing that when husbands were themselves not faithful, the waters could not function as an ordeal of the wife's faithfulness alone.</p>",
        "28": "<p>If innocent, <em>wəniqqətâ wənizerəʿâ zāraʿ</em> — she shall be free and shall conceive children. The positive outcome for the innocent woman is fertility rather than mere acquittal. The ordeal does not merely clear her name; it actively blesses her with the covenant blessing of offspring. This is an extraordinary legal guarantee: an innocent woman who has been falsely suspected and subjected to the humiliating ordeal is not merely vindicated but blessed. The law protects her against the social damage of accusation.</p>",
        "29": "<p>The legal summary: <em>zōʾt tôrat haqqənāʾôt</em> — this is the law of jealousy. The closing rubric mirrors the summaries of the purity laws above and anticipates the Nazirite law summary in 6:21. The word <em>tôrâ</em> here marks the jealousy-ordeal as a formal legal category with its own designated procedure.</p>",
        "30": "<p>The law covers both scenarios: a man whose wife has actually gone astray, and a man overcome by jealousy when his wife has not strayed. The symmetry of coverage — guilty and innocent alike go through the same procedure — establishes that the purpose of the law is to produce divine determination, not to assume guilt. The law is designed for epistemic situations where human evidence is absent, not for punishment of known guilt.</p>",
        "31": "<p><em>wəniqqa hāʾîš mēʿāwōn wəhāʾiššâ hahîʾ tiśśāʾ ʾet-ʿăwōnāh</em> — the man shall be free of guilt, and the woman shall bear her own iniquity. The asymmetry here — the husband's guilt is removed regardless, the wife bears her iniquity if guilty — has drawn significant critical attention. The law exempts the husband from any parallel ordeal for his own potential unfaithfulness. The ANE context and the patriarchal household structure of ancient Israel explain the asymmetry historically, even as later tradition (and the NT's ethic of mutual fidelity) reads beyond it. What the law does guarantee is that the guilty wife is judged by YHWH alone — no human punishment is authorized unless guilt is supernaturally confirmed.</p>"
    }
}

def main():
    data = load_comm('mkt-context', 'numbers')
    merge_comm(data, NUMBERS)
    save_comm('mkt-context', 'numbers', data)

main()
